using System;
using Microsoft.EntityFrameworkCore;
class AppDbContext : DbContext
{
    public DbSet<Order> Orders => Set<Order>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // EF Core 9: HasData values must be deterministic — DateTime.UtcNow causes
        // "pending model changes" exception on Migrate(). Use a fixed constant.
        modelBuilder.Entity<Order>().HasData(
            new Order { Id = 1, CreatedAt = new DateTime(2024, 1, 1, 0, 0, 0, DateTimeKind.Utc) });

        // EF Core 9 Cosmos DB: default discriminator property renamed from
        // "Discriminator" to "$type". Preserve old name for existing documents.
        // modelBuilder.Entity<YourCosmosEntity>().HasDiscriminator<string>("Discriminator");

        // EF Core 9 Cosmos DB: id property no longer contains discriminator prefix.
        // Preserve old compound format so existing documents remain accessible.
        // modelBuilder.Entity<YourCosmosEntity>().HasRootDiscriminatorInJsonId(true);
    }
}
class Order { public int Id { get; set; } public DateTime CreatedAt { get; set; } }

