using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    void ApplyMigrations(AppDbContext db)
    {
        var strategy = db.Database.CreateExecutionStrategy();
        strategy.Execute(() =>
        {
            using var transaction = db.Database.BeginTransaction();
            db.Database.Migrate();
            transaction.Commit();
        });
    }
}

arguments.new_str:
using System.Threading;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;
class MigrationRunner
{
    // EF Core 9: Migrate() now manages its own transactions and ExecutionStrategy.
    // Wrapping in a user transaction throws. Simply call MigrateAsync directly.
    // Also: Cosmos DB provider no longer supports sync I/O — use async equivalents.
    async Task ApplyMigrationsAsync(AppDbContext db, CancellationToken ct = default)
    {
        await db.Database.MigrateAsync(ct);
    }
}

